import type React from 'react';
import { COMPONENT_VERSION_ID } from '../config-provider';
import { UD_TREE_NODE_ID } from './common';
import type { TreeNodeProps } from './interface';

import './style';

export const TreeNode: React.FC<TreeNodeProps> = () => null;
if (__DEV__) {
  TreeNode.displayName = 'TreeNode';
}
Object.assign(TreeNode, {
  [UD_TREE_NODE_ID]: true,
  [COMPONENT_VERSION_ID]: process.env.__VERSION__,
});
